import{_ as e,o as a,c as r,ae as i}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Snap Log-Level Reporting","description":"","frontmatter":{"title":"Snap Log-Level Reporting","slug":"log-level-reporting-snap"},"headers":[],"relativePath":"account-hub/log-level-reporting-snap.md","filePath":"account-hub/log-level-reporting-snap.md"}'),d={name:"account-hub/log-level-reporting-snap.md"};function n(l,t,o,s,p,c){return a(),r("div",null,[...t[0]||(t[0]=[i('<p>Snap has introduced upcoming restrictions for User-Level Raw Data Exports (‘Log-Level Restrictions’) that will impact <em>all</em> third party MMP platforms that work with Snap 👻 Branch customers will experience the effects of this change starting <strong>January 3rd, 2024</strong>.</p><h3 id="impact" tabindex="-1">Impact <a class="header-anchor" href="#impact" aria-label="Permalink to &quot;Impact&quot;">​</a></h3><p>With this change, Snap is requiring log-level data to be scrubbed. There will be restrictions to log-level view-through conversion data, limiting certain fields such as campaign-level data and timestamps. This impacts the following Branch products:</p><ul><li>The Daily Exports, Custom Exports, and Scheduled Log Exports APIs</li><li>Third-party Data Integrations</li><li>Webhooks</li><li>Ad Partner Postbacks</li></ul><p>Advertisers can still see Snap as a media source for view-through conversions; however, campaign-level breakdowns will be unavailable for raw data exports. Campaign-level aggregate data will continue to be provided through the Branch Dashboard, aggregate-level APIs, and through Snap&#39;s own reporting interfaces/APIs.</p><h3 id="de-identifying-data" tabindex="-1">De-identifying Data <a class="header-anchor" href="#de-identifying-data" aria-label="Permalink to &quot;De-identifying Data&quot;">​</a></h3><p>For attribution reports that include view-through engagement, Branch will make the following adjustments to de-identify such data:</p><ul><li><p>The Media Source (PID) will be Snapchat, and will not otherwise be obfuscated or restricted.</p></li><li><p>Snap campaign information will be removed, specifically:</p><ul><li>Ad Account ID</li><li>Campaign ID</li><li>Ad Squad ID</li><li>Ad ID (and associated names)</li></ul></li><li><p>Attributed touch time will be reported as date only (dd/mm/yyyy)</p></li><li><p>Deep link URI information will be removed</p></li></ul><h3 id="restricted-parameters" tabindex="-1">Restricted Parameters <a class="header-anchor" href="#restricted-parameters" aria-label="Permalink to &quot;Restricted Parameters&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Snap Parameter</th><th>Branch Parameter</th></tr></thead><tbody><tr><td>ad_account_id</td><td>~advertising_account_id</td></tr><tr><td>campaign_id</td><td>~campaign_id</td></tr><tr><td>campaign_name</td><td>~campaign</td></tr><tr><td>ad_squad_id</td><td>~ad_set_id</td></tr><tr><td>ad_squad_name</td><td>~ad_set_name</td></tr><tr><td>ad_id</td><td>~ad_id</td></tr><tr><td>ad_name</td><td>~ad_name</td></tr><tr><td>country</td><td>~country_or_region</td></tr><tr><td>request_id</td><td>N/A</td></tr><tr><td>snap_channel</td><td>~secondary_publisher</td></tr><tr><td>deep_link_url</td><td>external_intent_uri, universal_link_url, android_app_link_url</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Ready to learn more about our Snap integration? View our guide here: <a href="./snap.html">Snap</a></p></div>',11)])])}const m=e(d,[["render",n]]);export{u as __pageData,m as default};
